class Solution {
public:
    int minStartingIndex(string s, string pattern) {
        int minIndex = -1;
        for (int i = 0; i <= s.length() - pattern.length(); i++) {
            int diffCount = 0;
            for (int j = 0; j < pattern.length(); j++) {
                if (s[i + j] != pattern[j]) {
                    diffCount++;
                    if (diffCount > 1) {
                        break;
                    }
                }
            }
            if (diffCount <= 1) {
                return i;
            }
        }
        return minIndex;
    }
};

